`endprotected

  
  //----------------------------------------------------------------------------
  /** This method calculates Parity by XORing input bytes */
  extern virtual function bit[`SVT_SPI_DATA_WIDTH-1:0] calculate_crc_parity(ref bit [`SVT_SPI_DATA_WIDTH-1:0] tx_data[]);

  //----------------------------------------------------------------------------
  /** 
   * This method calculates Chunk Parity for Read Memory, Program Memory and
   * multiple byte registers
   */
  extern virtual function bit[`SVT_SPI_DATA_WIDTH-1:0] calculate_current_data_chunk_parity(svt_spi_transaction xact);

  //----------------------------------------------------------------------------
  /** This method compares CRC Parity for Read Memory, Program Memory and multiple byte registers */
  extern virtual function void compare_crc_parity_for_multiple_byte_transfer(svt_spi_transaction xact,int crc_iteration_index);

  //----------------------------------------------------------------------------
  /** This method compares CRC Parity for 1byte Read and Write Registers */
  extern virtual function void compare_crc_parity_for_one_byte_register_transfer(svt_spi_transaction xact,int crc_iteration_index);

  //----------------------------------------------------------------------------
  /** This method checks that Partial Program to a Page is not more than specified amount */
  extern virtual function bit check_partial_page_program_parameters(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** This method Updates Partial Program related parameters upon successful completion of Page Program Operation */
  extern virtual function void update_partial_page_program_parameters(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** This method updates Permanent Block Lock Table with current Protected Blocks */
  extern virtual function void update_permanent_block_lock_protection_list(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** This method checks if unique id bytes are complemented or not.*/
  extern virtual function void check_unique_id_bytes_complement(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** return whether the Release from Deep Power Down command with Read Device ID
   * is valid or not based on part number.
   */
  extern virtual function bit whether_spi_flash_release_from_deep_power_down_with_device_id_is_valid();

  //----------------------------------------------------------------------------
  /** Check whether the current Protocol Mode is allowed Status Register Polling at power up. */
  extern virtual function void check_protocol_mode_during_polling_allowed_at_power_up();

  //----------------------------------------------------------------------------
  /** Check whether Status Register Polling is applicable to current part number. */
  extern virtual function bit whether_polling_check_at_power_up_is_applicable();

  //----------------------------------------------------------------------------
  /** 
   * This method returns whether current decoded command supports Hybrid Wrap Feature. 
   * Ex: in APMEMORY, LINEAR BURST Sync Commands overrides Hybrid Wrap 
   */
  extern virtual function bit whether_spi_flash_hybrid_wrap_is_valid();

  //----------------------------------------------------------------------------
  /**
   * This method returns whether current decoded command supports RBX Feature. 
   * Ex: in APMEMORY device family "OB" parts only LINEAR BURST Sync Read Commands is valid
   * RBX is same as Page Boundary Crossing
   */
  extern virtual function bit whether_spi_flash_rbx_feature_is_applicable(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** This method sets the Flash Mode Register Type. */
  extern virtual function void set_flash_mode_register_op();

  //----------------------------------------------------------------------------
  /** This method returns the transmit count required for the transmission of
   * XIP confirmation bits.
   */
  extern virtual function int get_xip_confirmation_bits_transmit_count(svt_spi_transaction in_xact);  

  // ---------------------------------------------------------------------------
  /** This task calculates CRC value for SAFE SPI for IN FRAME and OUT OF FRAME */
  extern virtual function bit [31:0] calculate_spi_safe_crc(bit[`SVT_SPI_SAFE_MAX_FRAME_WIDTH-1:0] tx_spi_safe_frame,svt_spi_types::direction_enum direction);

  //----------------------------------------------------------------------------
  /**
   * This Method updates the address_segment with the four byte address input
   * when configuration parameter enable_extended_register_update_with_four_byte_command_address is enabled.
   */ 
  extern virtual function void extended_register_update_with_four_byte_command_address(bit[`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] address);

  // ---------------------------------------------------------------------------
  /** This function checks if Minimum Page Write Size is met by Controller */
  extern virtual function void check_min_page_burst_length(svt_spi_transaction xact);

  // ---------------------------------------------------------------------------
  /** This task Checks that only valid commands are allowed suring Suspend Latency Timer must be met by Controller*/
  extern virtual task check_spi_flash_operation_allowed_when_suspend_latency_in_progress(svt_spi_transaction out_xact);

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Slave Select Deassert duration must be met by Controller*/
  extern virtual task check_slave_select_deselect_time(svt_spi_types::flash_command_enum prev_flash_command,bit prev_dtr_mode);

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Half Sleep duration must be met by Controller*/
  extern virtual task check_min_half_sleep_duration();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Exit Half Sleep Command Width duration must be met by Controller*/
  extern virtual task check_exit_half_sleep_width_duration();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Exit Half Sleep SS_N assert to SCLK setup time duration must be met by Controller*/
  extern virtual task check_exit_half_sleep_slave_select_assert_to_sclk_setup_time_duration();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Deep power Down duration must be met by Controller*/
  extern virtual task check_min_deep_power_down_duration();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Exit Deep Power Down Command Width duration must be met by Controller*/
  extern virtual task check_exit_deep_power_down_width_duration();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Exit Deep Power Down SS_N assert to SCLK setup time duration must be met by Controller*/
  extern virtual task check_exit_deep_power_down_slave_select_assert_to_sclk_setup_time_duration();

  //----------------------------------------------------------------------------
  /**
   * This Method determines Timing Parameter value as per the vendor SDR/DDR
   * AC Characterstics and from class timing cfg.
   * These parameters should not be scaled down.
   */ 
  extern virtual function real get_spi_flash_timing_check_parameter(string parameter_name = "",svt_spi_types::flash_command_type_enum flash_command_type = svt_spi_types::WRITE_REGISTER_TYPE,svt_spi_types::flash_command_enum flash_command = svt_spi_types::NULL_OPCODE, bit dtr_mode = 0);

  //----------------------------------------------------------------------------
  /** 
   * This Method determines Timing Parameter value as per the vendor from
   * class timing cfg
   */
  extern virtual function real get_spi_flash_timing_cfg_parameters(string parameter_name = "");

  //----------------------------------------------------------------------------
  /**
   * This method checks SCLK Pulse duration.
   */ 
  extern virtual function void do_sclk_pulse_duration_check(svt_spi_transaction xact);

  //----------------------------------------------------------------------------
  /** This method checks SCLK Pulse duration according to duty cycle */
  extern virtual function void do_sclk_duty_cycle_pulse_duration_check(svt_spi_transaction xact);    

  //----------------------------------------------------------------------------
  /** This method returns the sclk period scaling value for SCLK Period check */
  extern virtual function real get_sclk_period_scaling_value(svt_spi_types::flash_command_enum flash_command);    
  
  //----------------------------------------------------------------------------
  /**
   * This method checks whether to defer check evaluation till particular
   * event is reached.
   */ 
  extern virtual function bit is_ready_for_sclk_setup_hold_time_check();

  //----------------------------------------------------------------------------
  /**
   * This method checks Hold Timing Constraint for SPI Flash
   */ 
  extern virtual function void do_flash_hold_duration_check();

  //----------------------------------------------------------------------------
  /**
   * This method checks Setup Timing Constraint for SPI Flash
   */ 
  extern virtual function void do_flash_setup_duration_check();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Slave Select SetUp duration must be met by Controller for SPI flash mode.*/
  extern virtual task check_spiflash_slave_select_setup_time_ns(bit dtr_mode = 0);

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Leading time must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spibus_leading_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Leading time(Expressed in sclk) must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spibus_event_based_leading_time(int cnt_bus_clk_event);

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum trailing time must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spibus_trailing_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum IDLE duration between SPI Bus Transfer must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spibus_idle_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum IDLE duration(Expressed in half sclk) between SPI Bus Transfer must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spibus_event_based_idle_time(int cnt_idle_state_bus_clk);

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Leading time must be met by Controller for SPI SAFE mode.*/
  extern virtual task check_spi_safe_leading_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum trailing time must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spi_safe_trailing_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum IDLE duration between SPI Bus Transfer must be met by Controller for SPI Bus mode.*/
  extern virtual task check_spi_safe_idle_time();

  //----------------------------------------------------------------------------
  /** This method checks MOSI Setup Timing Constraint for SPI SAFE */
  extern virtual task check_spi_safe_mosi_setup_time_parameters();

  //----------------------------------------------------------------------------
  /** This method checks MOSI Hold Timing Constraint for SPI SAFE */
  extern virtual task check_spi_safe_mosi_hold_time_parameters();

  // ---------------------------------------------------------------------------
  /** This method checks MISO Data Valid Time wrt SS_N */
  extern virtual task check_spi_safe_ss_n_assert_to_miso_data_valid_time();

  // ---------------------------------------------------------------------------
  /** This method checks MISO Setup Timing Constraint for SPI SAFE */
  extern virtual task check_spi_safe_sclk_tx_edge_to_miso_data_valid_time_parameters();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum Slave Select Hold duration must be met by Controller*/
  extern virtual task check_slave_select_hold_time_ns(bit dtr_mode = 0);

  // ---------------------------------------------------------------------------
  /** This task Checks that Min and Max Slave Select Pulse Width durations must be met by Controller*/
  extern virtual task check_slave_select_assert_width_ns();

  // ---------------------------------------------------------------------------
  /** This task Checks that Min Read and Write Cycle Time durations must be met by Controller*/
  extern virtual task check_rd_wr_cycle_duration_ns();

  // ---------------------------------------------------------------------------
  /** This task check length of CS# LOW period to cause an exit from Deep Power Down*/
  extern virtual task sample_ss_n_assert_time_ns();

  // ---------------------------------------------------------------------------
  /** This function check following timing parameter:
   *   Read-Write Recovery Timer (tRWR)
   */
  extern virtual function void check_read_write_recovery_time();

  // ---------------------------------------------------------------------------
  /** This function check following timing parameter:
   *   Initial Latency Timer (tACC)
   */
  extern virtual function void check_initial_access_time(real latency_access_time_ns, int wait_cycle_count_multiple);

  // ---------------------------------------------------------------------------
  /** This task Checks that when SS_n is de-asserted Minimum Slave Select Set Up and Hold duration must be met by Controller*/
  extern virtual task check_idle_phase_ss_n_setup_and_hold_time_ns(bit prev_dtr_mode);

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum WP# Set up duration must be met by Controller*/
  extern virtual task check_write_protect_setup_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum WP# Hold duration must be met by Controller*/
  extern virtual task check_write_protect_hold_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum set up time for Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_active_setup_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum hold time for Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_active_hold_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum set up time for Non-Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_non_active_setup_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum hold time for Non-Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_non_active_hold_time();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum set up time(From SCLK Edge to HOLD Pin De-Assert) for Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_active_setup_duration_from_sclk_edge_to_hold_pin_deassert();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum hold time(From Hold Pin Assert to Next SCLK Edge) for Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_active_hold_duration_from_hold_pin_assert_to_next_sclk_edge();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum set up time(From SCLK Edge to HOLD Pin Assert) for Non Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_non_active_setup_duration_from_sclk_edge_to_hold_pin_assert();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum hold time(From Hold Pin De-Assert to Next SCLK Edge) for Non Active HOLD must be met by Controller*/
  extern virtual task check_hold_feature_non_active_hold_duration_from_hold_pin_deassert_to_next_sclk_edge();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum and Maximum RBX time for RBX enabled devices must be met by Slave Devices*/
  extern virtual task check_rbx_duration_ns();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum duration for CS Low to DQS Low is met by Slave Devices */
  extern virtual task check_dqs_active_time_ns();  

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum duration for DQS Last Edge to CS High */
  extern virtual function void check_dqs_inactive_time_ns();

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum DQS Pulse Width Duration is met by Slave Devices */
  extern virtual function void check_min_dqs_pulse_width_ns();    

  // ---------------------------------------------------------------------------
  /** This task Checks that Minimum time duration between Resume and next Suspend must be met by Controller */
  extern virtual task check_min_pass_unlock_to_next_pass_unlock_time_ns(real last_pass_unlock_command_time_ns);

  // ---------------------------------------------------------------------------
  /** This task determines whether Parallel Mode is enabled or not based on received flash command. */
  extern virtual function bit whether_parallel_io_enabled(svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /**
   * This method creates an object of type svt_spi_txrx_spi_flash_cmd_processor 
   * when a valid program/erase/write command that requires modeling timing delay is
   * detected at Slave device. It invokes the timing delay operation in
   * background while slave gets ready to detect the next transaction on SPI bus.
   * The list of such pending objects is maintained in flash_pending_cmd_processor queue.
   */ 
  extern virtual task submit_flash_command_to_cmd_processor(svt_spi_transaction out_xact);

  // ---------------------------------------------------------------------------
  /** 
   * Process the Interface activation command based on sub command code
   */ 
  extern virtual task process_spi_flash_interface_activation_command(svt_spi_transaction flash_xact);

  // ---------------------------------------------------------------------------
  /** This method clears flag at all locations in valid_nand_cache_register. */
  extern virtual task clear_valid_nand_cache_register_flag(bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] plane_select =0);

  //----------------------------------------------------------------------------
  /**
   * This Task updates the nor_cache_register using value from shared_status rxd_register index
   * which are updated by SPI Controller over SPI Bus.
   */ 
  extern virtual task update_cache_register_with_received_data(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /** This method checks whether the current accessed memory block is in Erased State or not.   */
  extern virtual function bit check_whether_rcvd_memory_block_in_erase_state(svt_spi_transaction xact);

  //----------------------------------------------------------------------------
  /** [For Profile 2.0]: This method checks whether the current accessed memory block is in Erased State or not.   */
  extern virtual function bit check_whether_rcvd_memory_block_in_erase_state_prfl_2_0(svt_spi_transaction xact);

  //----------------------------------------------------------------------------
  /** 
   * This method checks whether write to nonvolatile status register is valid and report an error if any write 
   * is attempted to a lock OTP or protected field. 
   */
  extern virtual function bit check_whether_write_status_register_valid(svt_spi_transaction xact);

  //----------------------------------------------------------------------------
  /** 
   * This method is called to check whether Program ASP commands is valid or not.
   * This task return 1 if valid
   */ 
  extern virtual function bit check_whether_asp_register_is_programmable(svt_spi_types::flash_command_enum flash_command,bit [63:0] reg_val);

  //----------------------------------------------------------------------------
  /** This method assign the mem_sequencer pointer*/
  extern function void set_flash_mem_sequencer(svt_mem_sequencer mem_sequencer);

  //----------------------------------------------------------------------------
  /** This method is used to retrive the mem_sequencer handle*/
  extern function svt_mem_sequencer get_flash_mem_sequencer();

  //----------------------------------------------------------------------------
  /**
   * This task executes the PAGE_PROGRAM command sampled at SPI Flash
   * Device when ECC Feature is Enabled.
   * This calculates Page Address and stores complete page in nor_data_register.
   * Then it validates ECC,corrects ECC and sends to write to memory
   */ 
  extern virtual task process_nor_page_program_with_ecc_command(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /**
   * This task executes the Profile 2.0 PAGE_PROGRAM command sampled at SPI Flash
   * Device when either Write Buffer occurs or ECC Feature is Enabled.
   * This calculates Page Address and stores complete page in nor_data_register.
   * Then it validates ECC,corrects ECC and sends to write to memory
   */ 
  extern virtual task process_prfl_2_0_nor_page_program(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /** This method executes BUFFER TO MEMORY Write command */
  extern virtual task process_nor_buffer_to_memory_write_command(svt_spi_transaction flash_xact);

  // ---------------------------------------------------------------------------
  /** This method update security registers upon PROGRAM_SECURITY_REGISTERS command */
  extern virtual function void update_security_registers(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /**
   * This task executes the PROGRAM_EXECUTE command sampled at SPI Flash
   * Device.
   */ 
  extern virtual task process_program_execute_command(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /** This task executes PAGE READ command after timer finish */
  extern virtual task process_spi_flash_page_read_command(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /** This task copies data register to cache register upon command READ PAGE CACHE RANDOM and READ PAGE CACHE LAST. */
  extern virtual task copy_spi_flash_data_register_to_cache_register();

  //----------------------------------------------------------------------------
  /** This task copies memory page contents to data register upon command READ PAGE CACHE RANDOM. */
  extern virtual task process_spi_flash_read_page_cache_random_command(svt_spi_transaction flash_xact);

  // ---------------------------------------------------------------------------
  /** This method stores Memory Page to Cache Register at initialize for SPI Slave device. */
  extern virtual task read_mem_page_to_data_register(svt_mem_addr_t page_start_address);

  // ---------------------------------------------------------------------------
  /**
   * This task calculates the ECC value of page partition data.
   */
  extern virtual task calculate_page_partition_ecc(svt_configuration cfg, bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] plane_id, int partition);

  // ---------------------------------------------------------------------------
  /**
   * This task updates page partitioned ECC value to device memory(ECC parity
   * data locations in spare area). 
   */
  extern virtual task update_mem_with_page_partition_ecc_bytes(svt_configuration cfg, bit[`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] page_start_addr,
                                                               svt_spi_types::serial_queue calculated_ecc_parity_data, bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] plane_id, int partition);

  //----------------------------------------------------------------------------
  /** This method stores Memory Page to Data Register for SPI Slave device. */
  extern virtual task download_current_page_to_data_register(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /** 
   * This method is invoked when Program Memory or Read Memory
   * occurs and ECC enable is set. data register nor_data_register is used.
   * This method verifies if calculated ECC and ECC parity Bits results to
   * 0 when XOR'ed
   * The arguement "read_mem_txn" is currently used in Spansion "S28HS" part where
   * Address Trap Register and Counter updates for Read Txn only
   */ 
  extern virtual function void validate_nor_data_register_ecc_bytes(svt_mem_addr_t xact_address_frame, bit read_mem_txn = 1);

  //----------------------------------------------------------------------------
  /** 
   * This task updates the partial programmed and double partial programmed chunk lists.
   */
  extern virtual task update_partial_and_double_partial_program_chunk_list(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /**
   * This Task updates the NAND or NOR data_register using value from resp cache_register index
   * which are updated by SPI Controller over SPI Bus.
   */ 
  extern virtual task update_data_register_with_cache_data(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /**
   * This task calculates and updates ECC byte for NOR Flash device
   */ 
  extern virtual task calculate_and_update_nor_flash_ecc(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /**
   * This task uploads the Page from nor_data_register/nand_data_register to Page in Main memory
   */ 
  extern virtual task update_mem_core_with_data_register(svt_spi_transaction flash_xact);

  //----------------------------------------------------------------------------
  /** 
   * This method is invoked when Page Read to Data Register
   * (nand_data_register) occurs and ECC enable is set.
   * This method verifies if calculated ECC and ECC parity Bits results to
   * 0 when XOR'ed
   */ 
  extern virtual function void validate_nand_data_register_ecc_bytes(svt_mem_addr_t nand_data_page_address);

  //----------------------------------------------------------------------------
  /**
   * This task calculates and updates ECC byte in spare region
   */ 
  extern virtual task calculate_and_update_ecc(bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] plane_id = 0);

  // ---------------------------------------------------------------------------
  /** This method sets flag at all locations of valid_nand_cache_register. */
  extern virtual task assert_valid_nand_cache_register_flag(bit [`SVT_SPI_MAX_PLANE_SELECT_CFG_BIT_WIDTH-1:0] plane_select =0);
  
  //----------------------------------------------------------------------------
  /** 
   * This method is used to calculate the Starting read address at mem_core
   * when Read memory/XIP mode is detected. 
   */
  extern virtual function svt_mem_addr_t calculate_slave_mem_start_addr(svt_mem_addr_t rcvd_addr);

  //----------------------------------------------------------------------------
  /** This method checks whether current chunk is double programmed. (Currently for MX25UM/LM) */
  extern virtual function bit is_current_chunk_double_programmed(svt_mem_addr_t memory_block_chunk);

  //----------------------------------------------------------------------------
  /** 
   * This methods updates ECC Status in Configuration Register 2 when invoked.
   * This also records first double program address.
   */ 
  extern virtual function void update_ecc_status_if_double_programmed(svt_mem_addr_t memory_block_chunk);

  //----------------------------------------------------------------------------
  /** This method updates the memory with corrected byte after ECC detection and correction. */
  extern virtual function void update_memory_after_ecc_correction(svt_mem_addr_t data_page_address, int byte_location, bit [`SVT_SPI_DATA_WIDTH-1:0] rd_data);

  //----------------------------------------------------------------------------
  /** 
   * This method updates the memory with BAD Block mark when ECC is detected but not corrected. 
   * Bad Block is marked on page 0 of the block.
   */
  extern virtual function void update_memory_to_mark_bad_block(svt_mem_addr_t nand_data_page_address);

  //----------------------------------------------------------------------------
  /** Drive the payload according to byte endianness */
  extern virtual task transmit_payload(ref bit [`SVT_SPI_DATA_WIDTH-1:0] tx_data[], ref bit [`SVT_SPI_DATA_WIDTH-1:0] tx_valid[], input int num_lane=1);

  //----------------------------------------------------------------------------
  /**This method populates the txd_register with the slave read
   * data.txd_register is used to populate the slave response for all 
   * read commands, which is needed for trace file. 
   */ 
  extern virtual function void update_txd_register(int prev_size,int read_word_size);
  
  //----------------------------------------------------------------------------
  /** This task issues the callback "beat_ended" */
  extern virtual task issue_beat_ended_callback(bit [`SVT_SPI_DATA_WIDTH-1:0] txdata, bit[`SVT_SPI_MAX_ADDR_FRAME_WIDTH-1:0] address,int index_size);

  //----------------------------------------------------------------------------
  /** This method drives the calculated CRC on SPI Interface */
  extern virtual task transmit_crc_parity(bit [`SVT_SPI_DATA_WIDTH-1:0] data_crc_frame,int lane_count);

  // ---------------------------------------------------------------------------
  /** This task drives Slave Ready Signal on Configured Slave Id lane. Used for Slave only */
  extern virtual task drive_slave_rdy_signal(string operation);

  // ---------------------------------------------------------------------------
  /** 
   * This method checks whether received reset command is valid.
   * In ATXP part number, Reset is valid only if Reset confirmation byte is
   * received correctly
   */
  extern virtual function bit whether_spi_flash_reset_command_valid(svt_spi_transaction xact); 

  // ---------------------------------------------------------------------------
  /** This task drives Z or Pull Up-Down State on MOSI */
  extern virtual task drive_mosi_port_inactive_state();

  // ---------------------------------------------------------------------------
  /** This task calculates and returns CRC-32 value for the input address range. */
  extern virtual function bit [31:0] calculate_crc32(bit [`SVT_MEM_MAX_ADDR_WIDTH-1:0] start_addr, bit [`SVT_MEM_MAX_ADDR_WIDTH-1:0] stop_addr);

  // ---------------------------------------------------------------------------
  /** This task calculates and returns CRC-32 value for the input queue.
   * It use the following 32-bit polynomial (CRC-32C) to generate a CRC checksum
   * G(x) = X32 + X28 + X27 + X26 + X25 + X23 + X22 + X20 + X19 + X18 + X14 + X13 + X11 + X10 + X9 + X8 + X6  + 1
   */ 
  extern virtual function bit [31:0] fn_calculate_CRC32(input bit [31:0] initial_val, input bit [`SVT_SPI_DATA_WIDTH-1:0] spi_pkt_in [$]);

  //----------------------------------------------------------------------------
  /**
   * This method checks whether the Profile 2 Command detected by slave device is valid in
   * current device state. This also returns the next Profile 2.0 state.
   */ 
  extern virtual function bit check_spi_flash_profile_2_operation_allowed_in_device_state(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** 
   * This method checks whether the Profile 2 Command detected by slave device is valid in Program Suspended state.
   * This is also called in WREN2 State to check if the decoded command is valid.
   */ 
  extern virtual function bit check_spi_flash_profile_2_operation_allowed_in_program_suspend_device_state(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** 
   * This method checks whether the Profile 2 Command detected by slave device is valid in Erase Suspended state.
   * This is also called in WREN2/WORD_PROG State to check if the decoded command is valid.
   */ 
  extern virtual function bit check_spi_flash_profile_2_operation_allowed_in_erase_suspend_device_state(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** This method decodes Profile 2 command based on received instruction byte/address frame/data frame */
  extern virtual function svt_spi_types::flash_command_enum decode_xSPI_profile_2_0_flash_command_opcode(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /** This method decodes Profile 2 command based on received instruction byte/address frame/data frame in xSPI_S27KL_S27KS family*/
  extern virtual function svt_spi_types::flash_command_enum decode_xSPI_profile_2_0_s27kl_s27ks_flash_command_opcode(svt_spi_transaction out_xact, svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** This method decodes Profile 2 command based on received instruction byte/address frame/data frame in xSPI_S70KL_S70KS family*/
  extern virtual function svt_spi_types::flash_command_enum decode_xSPI_profile_2_0_s70kl_s70ks_flash_command_opcode(svt_spi_transaction out_xact, svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** This method decodes Profile 2 command based on received instruction byte/address frame/data frame in xSPI_S80KS family*/
  extern virtual function svt_spi_types::flash_command_enum decode_xSPI_profile_2_0_s80ks_flash_command_opcode(svt_spi_transaction out_xact, svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** This method decodes Profile 2 command based on received instruction byte/address frame/data frame in xSPI_IS66_67_WVO_M8D family*/
  extern virtual function svt_spi_types::flash_command_enum decode_xSPI_profile_2_0_is66_67_wvo_m8d_flash_command_opcode(svt_spi_transaction out_xact, svt_spi_types::flash_command_enum flash_command);

  //----------------------------------------------------------------------------
  /** 
   * This method executes the steps when a Write Register/Erase/program memory 
   * flash command is detected by Slave device in Profile 2.0 Mode
   */
  extern virtual task process_spi_flash_profile_2_0_slave_write_command(svt_spi_transaction out_xact);

  //----------------------------------------------------------------------------
  /* 
   * Updates the Internal register content when a Write Register command is triggered
   * by SPI master Agent in Profile 2.0 Mode
   */ 
  extern virtual task process_spi_flash_profile_2_0_master_write_command(svt_spi_transaction xact);

  //----------------------------------------------------------------------------
  /* 
   * Check if Read Password Protection Mode is active or not 
   */ 
  extern virtual function bit read_password_protection_mode_not_active();

  //----------------------------------------------------------------------------
  /* 
   * Modify the address value inside boot sector range when Read Password Protection
   * Mode is active.
   */ 
  extern virtual function svt_mem_addr_t calculate_address_from_boot_sector(svt_mem_addr_t addr);

  //----------------------------------------------------------------------------
  /* 
   * This task initialize the self refresh process.
   */ 
  extern virtual task initialize_self_refresh_memory();

  //----------------------------------------------------------------------------
  /* 
  * This task gets the self refresh array range (start row and end row).
   */ 
  extern virtual task get_self_refresh_array_range(output int start_row, output int end_row);
endclass


